// Subscribe to the removeFields delegate of BankSysTableFieldLookup
// This allows us to remove specific fields from the lookup dynamically
[SubscribesTo(classStr(BankSysTableFieldLookup),delegateStr(BankSysTableFieldLookup, removeFields))]
public static void removeFieldsForClearingDate(TmpSysTableField _allFields,TableId          _tableId)

{
    // Get ETG Canada parameters record
    ETGCanadaParameters etgParams = ETGCanadaParameters::find();

    if (_tableId != tableNum(BankReconciliationDocumentOpenTmp))
    {
        return;
    }
    if (!etgParams.EnableClearingDateReconciliation)
    {
        // Remove ClearingDate field from the lookup
        delete_from _allFields
            where _allFields.FieldId ==fieldNum(BankReconciliationDocumentOpenTmp, ClearingDate);

    }

}
